import java.util.Scanner;
import java.util.Arrays;

public class SecureBufferExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Ensure input length does not exceed buffer size
        int maxLength = 10;
        if (name.length() > maxLength) {
            System.out.println("Input exceeds maximum length.");
            return;
        }

        // Copy input into buffer safely
        byte[] buffer = new byte[maxLength];
        Arrays.fill(buffer, (byte) 0); // Initialize buffer with zeros
        System.arraycopy(name.getBytes(), 0, buffer, 0, name.length());

        System.out.println("Hello, " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
